import{_ as a,o as i,c as t,ag as e}from"./chunks/framework.CvgP6Fyv.js";const g=JSON.parse('{"title":"Hướng dẫn sử dụng (User Guide)","description":"Cẩm nang hướng dẫn tạo Data, vận hành và xử lý lỗi phần mềm HappyAgent","frontmatter":{"title":"Hướng dẫn sử dụng (User Guide)","description":"Cẩm nang hướng dẫn tạo Data, vận hành và xử lý lỗi phần mềm HappyAgent","robots":"index, follow"},"headers":[],"relativePath":"sop/user-guide.md","filePath":"sop/user-guide.md"}'),s={name:"sop/user-guide.md"};function h(o,n,l,r,c,p){return i(),t("div",null,[...n[0]||(n[0]=[e(`<h1 id="📖-huong-dan-su-dung-van-hanh-sop" tabindex="-1">📖 Hướng dẫn sử dụng &amp; Vận hành (SOP) <a class="header-anchor" href="#📖-huong-dan-su-dung-van-hanh-sop" aria-label="Permalink to &quot;📖 Hướng dẫn sử dụng &amp; Vận hành (SOP)&quot;">​</a></h1><p>Tài liệu này cung cấp các bước từ lúc cấu hình Data, chạy dự án cho đến khi khắc phục sự cố thông qua Healer 2.0.</p><h2 id="_1-moi-truong-chuan-bi" tabindex="-1">1. Môi trường chuẩn bị <a class="header-anchor" href="#_1-moi-truong-chuan-bi" aria-label="Permalink to &quot;1. Môi trường chuẩn bị&quot;">​</a></h2><ul><li><strong>Node.js</strong>: Máy tính cần cài đặt Node.js phiên bản <code>&gt;= 18.0.0</code>.</li><li><strong>Trình duyệt</strong>: Tool đã tích hợp sẵn ngầm <code>cloakbrowser</code> tự động tải xuống.</li><li><strong>API LLM</strong>: (Dành cho Healer) Cần cài đặt biến số API vào file <code>.env</code> (nếu có sử dụng các dạng Agent tích hợp qua CLI).</li></ul><hr><h2 id="_2-chuan-bi-cau-hinh-profile-data" tabindex="-1">2. Chuẩn bị (Cấu hình Profile &amp; Data) <a class="header-anchor" href="#_2-chuan-bi-cau-hinh-profile-data" aria-label="Permalink to &quot;2. Chuẩn bị (Cấu hình Profile &amp; Data)&quot;">​</a></h2><p>Trước khi chạy tool, bạn cần cung cấp Data qua việc thiết lập <code>config/profiles.json</code> và cấu hình các Creator cần mời thông qua <code>config/creators.csv</code>.</p><h3 id="tao-va-go-loi-profile-trinh-duyet-profiles-json" tabindex="-1">Tạo và gỡ lỗi Profile Trình duyệt (<code>profiles.json</code>) <a class="header-anchor" href="#tao-va-go-loi-profile-trinh-duyet-profiles-json" aria-label="Permalink to &quot;Tạo và gỡ lỗi Profile Trình duyệt (\`profiles.json\`)&quot;">​</a></h3><p>Mỗi Profile được xem như một chiếc máy tính ảo độc lập.</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;profiles&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;shop_1&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;path&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;./chrome_profiles/shop_1&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;fingerprintSeed&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;shop1_unique_seed&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">Lưu ý về Fingerprint</p><p>Không được đổi <code>fingerprintSeed</code> sau khi Shop đã đăng nhập thành công. Điều này sẽ khiến trang web hiểu lầm rằng bạn chuyển sang thiết bị khác!</p></div><h3 id="mau-tin-nhan-message-template" tabindex="-1">Mẫu tin nhắn (Message Template) <a class="header-anchor" href="#mau-tin-nhan-message-template" aria-label="Permalink to &quot;Mẫu tin nhắn (Message Template)&quot;">​</a></h3><p>Chỉnh sửa file <code>config/message-template.json</code> theo đúng cấu trúc.</p><hr><h2 id="_3-khoi-chay-van-hanh-orchestrator" tabindex="-1">3. Khởi chạy &amp; Vận hành (Orchestrator) <a class="header-anchor" href="#_3-khoi-chay-van-hanh-orchestrator" aria-label="Permalink to &quot;3. Khởi chạy &amp; Vận hành (Orchestrator)&quot;">​</a></h2><p>Luồng chạy chính của Project là <strong>Orchestrator</strong> - một hệ thống bash có khả năng tự reload lại chạy khi bị văng lỗi.</p><p><strong>Để khởi động:</strong></p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-SPdEf" id="tab-TPtrXzX" checked><label data-title="Terminal" for="tab-TPtrXzX">Terminal</label></div><div class="blocks"><div class="language-bash vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span></span></code></pre></div></div></div><p>Khi chạy, Terminal sẽ hiển thị các log thông báo (<code>[INFO]</code>) trạng thái duyệt qua từng Creator. Các báo cáo sau đó sẽ được đổ vào Output CSV.</p><p>Bạn có thể theo dõi Dashboard Local HTML (Mở <code>dashboard/index.html</code> trong thư mục bằng Live Server) để xem Visual Report trực quan.</p><hr><h2 id="_4-xu-ly-su-co-bao-tri-troubleshooting" tabindex="-1">4. Xử lý Sự cố &amp; Bảo trì (Troubleshooting) <a class="header-anchor" href="#_4-xu-ly-su-co-bao-tri-troubleshooting" aria-label="Permalink to &quot;4. Xử lý Sự cố &amp; Bảo trì (Troubleshooting)&quot;">​</a></h2><p>Hệ thống được thiết kế với sự hỗ trợ của thành phần AI ảo tên là <strong>Healer 2.0</strong>. Với mô hình 0-giờ-bảo-trì (Zero-Maintenance), khi xảy ra việc website TikTok bị cập nhật (ví dụ class <code>.button</code> bị đổi), bạn <strong>không cần thao tác</strong> gì. Tuy nhiên cần hiểu cách nó xử lý:</p><h3 id="qua-trinh-healer-giai-cuu" tabindex="-1">Quá trình Healer giải cứu <a class="header-anchor" href="#qua-trinh-healer-giai-cuu" aria-label="Permalink to &quot;Quá trình Healer giải cứu&quot;">​</a></h3><ol><li><strong>Orchestrator (Runner)</strong> phát hiện Selector bị lỗi Timeout $\\Rightarrow$ Crash hệ thống.</li><li><strong>Tracer</strong> xuất file Screenshot và HTML Snapshot ra thư mục <code>data/errors/</code>.</li><li><strong>Healer</strong> kích hoạt AI, phân tích HTML hiện thời và ghi đè Selector mới vào file mã máy.</li><li><strong>Local Test-Gate:</strong> Khởi tạo một phiên chạy Headless ngầm để test Selector AI vừa tạo bằng cách móc thẳng vào HTML cục bộ (không thông qua mạng Internet). <ul><li><em>Xác thực 1 phần tử (Valid):</em> Pass -&gt; Chạy lại tiến trình.</li><li><em>Khác 1 phần tử (Invalid):</em> Reject -&gt; Lưu báo cáo, AI nghĩ lại cách khác (tối đa 3 lần).</li></ul></li></ol><h3 id="can-thiep-thu-cong-neu-cap-bach" tabindex="-1">Can thiệp thủ công (Nếu cấp bách) <a class="header-anchor" href="#can-thiep-thu-cong-neu-cap-bach" aria-label="Permalink to &quot;Can thiệp thủ công (Nếu cấp bách)&quot;">​</a></h3><p>Trong trường hợp AI sau 3 lần Test-Gate vẫn thất bại (File log báo <code>Exhausted 3 attempts. Giving up</code>), bạn cần:</p><ol><li><p>Mở screenshot bị lỗi tại <code>data/errors/error_screenshot.png</code> xem TikTok đã hiển thị thế nào.</p></li><li><p>Vào <code>src/utils/selectors.js</code>.</p></li><li><p>Vá lại selector bằng tay ứng với giao diện mới.</p></li><li><p>Lưu file và kích hoạt lệnh khởi chạy lại (<code>npm start</code>).</p><p><em>Hệ thống Orchestrator sẽ tự chạy lại đúng Profile chứa Creator mà lúc nãy nó đang chạy dang dở.</em></p></li></ol>`,28)])])}const u=a(s,[["render",h]]);export{g as __pageData,u as default};
